sql:
SELECT DISTINCT T1.name
FROM carriers T1
JOIN flights T2 ON T1.code = T2.carrier;

SELECT AVG(arr_delay) AS average_arrival_delay
FROM flights
WHERE arr_delay > 0;

SELECT T1.carrier, T1.flight_num, T1.flight_distance, T1.dep_delay
FROM flights AS T1
WHERE T1.dep_delay = (
  SELECT MAX(dep_delay)
  FROM flights
);

SELECT AVG(flight_distance) AS average_flight_distance
FROM flights
WHERE carrier = 'B6' AND dep_delay > 30;

